/**
 * TizenClaw Bridge SDK v1.0
 *
 * Auto-injected into web apps generated by
 * generate_web_app. Provides a simple API for
 * web apps to call TizenClaw tools and receive
 * real-time events.
 *
 * Usage:
 *   const battery = await TizenClaw.callTool(
 *       'get_battery_info');
 *   TizenClaw.subscribe('battery.changed', cb);
 */
(function() {
  'use strict';

  // Auto-detect app_id from URL path
  // URL pattern: /apps/{app_id}/
  function detectAppId() {
    var m = window.location.pathname
        .match(/^\/apps\/([^/]+)/);
    return m ? m[1] : '';
  }

  var appId = detectAppId();

  /**
   * Call a TizenClaw tool via Bridge API.
   * @param {string} toolName - Tool name
   * @param {Object} [args] - Tool arguments
   * @returns {Promise<Object>} Tool result
   */
  function callTool(toolName, args) {
    return fetch('/api/bridge/tool', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        app_id: appId,
        tool_name: toolName,
        arguments: args || {}
      })
    })
    .then(function(res) { return res.json(); })
    .then(function(data) {
      if (data.status === 'error')
        throw new Error(data.error);
      return data.result;
    });
  }

  /**
   * Get list of available tools for this app.
   * @returns {Promise<Array>} Array of tool
   *   objects with name, description, params
   */
  function getAvailableTools() {
    var url = '/api/bridge/tools';
    if (appId)
      url += '?app_id=' +
          encodeURIComponent(appId);
    return fetch(url)
        .then(function(r) { return r.json(); })
        .then(function(d) { return d.tools; });
  }

  /**
   * Subscribe to EventBus events via SSE.
   * @param {string} topic - Event topic
   * @param {Function} callback - Handler
   * @returns {Function} Unsubscribe function
   */
  function subscribe(topic, callback) {
    var url = '/api/bridge/events?app_id=' +
        encodeURIComponent(appId) +
        '&topics=' +
        encodeURIComponent(topic);
    var source = new EventSource(url);
    source.onmessage = function(e) {
      try {
        var data = JSON.parse(e.data);
        callback(data);
      } catch (err) {
        callback({raw: e.data});
      }
    };
    source.onerror = function() {
      // Auto-reconnect is handled by browser
    };
    return function unsubscribe() {
      source.close();
    };
  }

  /**
   * Save app-specific data via Bridge API.
   * @param {string} key - Data key
   * @param {*} value - Data value
   * @returns {Promise<Object>} Result
   */
  function setData(key, value) {
    return fetch('/api/bridge/data', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        app_id: appId,
        key: key,
        value: value
      })
    }).then(function(r) { return r.json(); });
  }

  /**
   * Load app-specific data via Bridge API.
   * @param {string} key - Data key
   * @returns {Promise<*>} Stored value
   */
  function getData(key) {
    var url = '/api/bridge/data?app_id=' +
        encodeURIComponent(appId) +
        '&key=' + encodeURIComponent(key);
    return fetch(url)
        .then(function(r) { return r.json(); })
        .then(function(d) { return d.value; });
  }

  /**
   * Send a prompt to TizenClaw LLM.
   * @param {string} prompt - Natural language
   * @returns {Promise<string>} LLM response
   */
  function askLLM(prompt) {
    return fetch('/api/chat', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        prompt: prompt,
        session_id: 'webapp_' + appId
      })
    })
    .then(function(r) { return r.json(); })
    .then(function(d) { return d.response; });
  }

  // Expose global TizenClaw namespace
  window.TizenClaw = {
    appId: appId,
    callTool: callTool,
    getAvailableTools: getAvailableTools,
    subscribe: subscribe,
    setData: setData,
    getData: getData,
    askLLM: askLLM,
    version: '1.0.0'
  };
})();
